cat > internal/channels/pancake/post_fetcher.go <<'EOF'
package pancake

import (
	"context"
	"sync"
	"time"

	"golang.org/x/sync/singleflight"
)

const defaultPostCacheTTL = 15 * time.Minute

// postCacheEntry holds the page's post list indexed by canonical post ID.
type postCacheEntry struct {
	posts     map[string]*PancakePost
	expiresAt time.Time
}

// PostFetcher fetches and caches Pancake post content for comment context.
// Pancake exposes posts as a page-level list, so concurrent misses share one
// singleflight key ("posts") instead of fetching each post independently.
type PostFetcher struct {
	apiClient *APIClient
	cacheTTL  time.Duration
	cache     sync.Map          // "posts" → *postCacheEntry
	sfGroup   singleflight.Group // coalesces concurrent page post-list fetches
}

// NewPostFetcher creates a PostFetcher with the given cache TTL string.
func NewPostFetcher(client *APIClient, cacheTTLStr string) *PostFetcher {
	ttl := defaultPostCacheTTL
	if cacheTTLStr != "" {
		if d, err := time.ParseDuration(cacheTTLStr); err == nil && d > 0 {
			ttl = d
		}
	}
	return &PostFetcher{apiClient: client, cacheTTL: ttl}
}

// GetPost returns the requested post from the cached page post list.
func (pf *PostFetcher) GetPost(ctx context.Context, postID string) (*PancakePost, error) {
	if pf == nil || pf.apiClient == nil || postID == "" {
		return nil, nil
	}
	posts, err := pf.getPosts(ctx)
	if err != nil {
		return nil, err
	}
	return posts[postID], nil
}

func (pf *PostFetcher) getPosts(ctx context.Context) (map[string]*PancakePost, error) {
	const cacheKey = "posts"
	if v, ok := pf.cache.Load(cacheKey); ok {
		entry := v.(*postCacheEntry)
		if time.Now().Before(entry.expiresAt) {
			return entry.posts, nil
		}
		pf.cache.Delete(cacheKey)
	}

	val, err, _ := pf.sfGroup.Do(cacheKey, func() (any, error) {
		if v, ok := pf.cache.Load(cacheKey); ok {
			entry := v.(*postCacheEntry)
			if time.Now().Before(entry.expiresAt) {
				return entry.posts, nil
			}
		}

		list, err := pf.apiClient.ListPosts(ctx)
