package pancake

import (
	"fmt"
	"log/slog"
	"strings"

	"github.com/nextlevelbuilder/goclaw/internal/channels"
)

// handleCommentEvent converts a Pancake COMMENT webhook event to an inbound agent message.
func (ch *Channel) handleCommentEvent(data MessagingData) {
	if !ch.config.Features.CommentReply {
		return
	}
	if data.PageID != "" && data.PageID != ch.pageID {
		return
	}
	if data.Message.SenderID == ch.pageID {
		return
	}
	if isAssignedStaff(data.AssigneeIDs, data.Message.SenderID) {
		return
	}
	if data.Message.SenderID == "" {
		slog.Warn("pancake: comment missing sender_id, skipping", "comment_id", data.CommentID, "msg_id", data.Message.ID)
		return
	}

	commentID := data.CommentID
	if commentID == "" {
		commentID = data.Message.ID
	}
	var dedupKey string
	if commentID != "" {
		dedupKey = "comment:" + commentID
		if ch.isDup(dedupKey) {
			slog.Debug("pancake: duplicate comment event skipped", "comment_id", commentID)
			return
		}
	}

	if !ch.commentPassesFilter(data.Message.Content) {
		return
	}

	// Check outbound echo before buildCommentContent adds post context or prefixes.
	if ch.isRecentOutboundEcho(data.ConversationID, data.Message.Content) {
		slog.Info("pancake: skipping recent outbound comment echo",
			"page_id", ch.pageID,
			"conversation_id", data.ConversationID,
			"comment_id", commentID)
		return
	}

	chatID := data.ConversationID
	if chatID == "" {
		chatID = fmt.Sprintf("%s:%s", data.PostID, data.Message.SenderID)
	}

	metadata := map[string]string{
		"pancake_mode":        "comment",
		"conversation_type":   "COMMENT",
		"platform":            data.Platform,
		"conversation_id":     data.ConversationID,
		"comment_id":          commentID,
		"post_id":             data.PostID,
		"parent_id":           data.ParentID,
		"sender_id":           data.Message.SenderID,
		"sender_name":         data.Message.SenderName,
		"reply_to_comment_id": commentID,
		"message_id":          dedupKey,
		"display_name":        channels.SanitizeDisplayName(data.Message.SenderName),
		"page_name":           ch.pageName,
	}

	ch.HandleMessage(data.Message.SenderID, chatID, ch.buildCommentContent(data), nil, metadata, "direct")
}

func (ch *Channel) commentPassesFilter(content string) bool {
	filter := strings.ToLower(strings.TrimSpace(ch.config.CommentReplyOptions.Filter))
	if filter == "" || filter == "all" {
		return true
	}
	if filter != "keyword" {
		return false
	}

	content = strings.ToLower(stripHTML(content))
	for _, keyword := range ch.config.CommentReplyOptions.Keywords {
		keyword = strings.ToLower(strings.TrimSpace(keyword))
		if keyword != "" && strings.Contains(content, keyword) {
			return true
		}
	}
	return false
}

func (ch *Channel) buildCommentContent(data MessagingData) string {
	content := buildMessageContent(data)
	if !ch.config.CommentReplyOptions.IncludePostContext {
		return content
	}

	postText := data.Post.Text()
	if postText == "" && ch.postFetcher != nil && data.PostID != "" {
		post, err := ch.postFetcher.GetPost(ch.stopCtx, data.PostID)
		if err == nil && post != nil {
			postText = post.Text()
		} else if err != nil {
			slog.Warn("pancake: fetch post context failed", "post_id", data.PostID, "err", err)
		}
	}
	if postText == "" {
		return content
	}
	return "[Post] " + stripHTML(postText) + "\n\n" + content
}
EOF

