    }, "send attachment message")
}

// ReplyComment posts a public reply to a Pancake comment conversation.
func (c *APIClient) ReplyComment(ctx context.Context, conversationID, commentID, content string) error {
    return c.sendConversationMessage(ctx, conversationID, SendMessageRequest{
        Action:    "reply_comment",
        Message:   content,
        CommentID: commentID,
    }, "reply comment")
}

// PrivateReply sends a first-inbox private reply to a commenter.
func (c *APIClient) PrivateReply(ctx context.Context, conversationID, commentID, content string) error {
    return c.sendConversationMessage(ctx, conversationID, SendMessageRequest{
        Action:    "private_reply",
        Message:   content,
        CommentID: commentID,
    }, "private reply")
}

