    81	func (ch *Channel) commentPassesFilter(content string) bool {
    82		filter := strings.ToLower(strings.TrimSpace(ch.config.CommentReplyOptions.Filter))
    83		if filter == "" || filter == "all" {
    84			return true
    85		}
    86		if filter != "keyword" {
    87			return false
    88		}
    89	
    90		content = strings.ToLower(stripHTML(content))
    91		for _, keyword := range ch.config.CommentReplyOptions.Keywords {
    92			keyword = strings.ToLower(strings.TrimSpace(keyword))
    93			if keyword != "" && strings.Contains(content, keyword) {
    94				return true
    95			}
    96		}
    97		return false
    98	}
