   100	func (ch *Channel) buildCommentContent(data MessagingData) string {
   101		content := buildMessageContent(data)
   102		if !ch.config.CommentReplyOptions.IncludePostContext {
   103			return content
   104		}
   105	
   106		postText := data.Post.Text()
   107		if postText == "" && ch.postFetcher != nil && data.PostID != "" {
   108			ctx := ch.stopCtx
   109			if ctx == nil {
   110				ctx = context.Background()
   111			}
   112			post, err := ch.postFetcher.GetPost(ctx, data.PostID)
   113			if err == nil && post != nil {
   114				postText = post.Text()
   115			} else if err != nil {
   116				slog.Warn("pancake: fetch post context failed", "post_id", data.PostID, "err", err)
   117			}
   118		}
   119		if postText == "" {
   120			return content
   121		}
   122		return "[Post] " + stripHTML(postText) + "\n\n" + content
   123	}

