   186	func (ch *Channel) sendInboxReply(ctx context.Context, msg bus.OutboundMessage) error {
   187		conversationID := msg.ChatID
   188		if conversationID == "" {
   189			return fmt.Errorf("pancake: chat_id (conversation_id) is required for outbound message")
   190		}
   191	
   192		text := FormatOutbound(msg.Content, ch.platform)
   193	
   194		// Handle media attachments.
   195		attachmentIDs, err := ch.handleMediaAttachments(ctx, msg)
   196		if err != nil {
   197			slog.Warn("pancake: media upload failed, sending text only",
   198				"page_id", ch.pageID, "err", err)
   199		}
   200	
   201		// Pancake's official contract makes `message` and `content_ids` mutually exclusive.
   202		// Deliver uploaded media first, then follow with text chunks if needed.
   203		if len(attachmentIDs) > 0 {
   204			if err := ch.apiClient.SendAttachmentMessage(ctx, conversationID, attachmentIDs); err != nil {
   205				ch.handleAPIError(err)
   206				return err
   207			}
   208			if text == "" {
   209				return nil
   210			}
   211		}
   212	
   213		// Text-only: split into platform-appropriate chunks.
   214		// Store echo fingerprints BEFORE sending so that webhook echoes arriving
   215		// while the HTTP round-trip is in flight are already recognized as self-sent.
   216		parts := splitMessage(text, ch.maxMessageLength())
   217		for _, part := range parts {
   218			ch.rememberOutboundEcho(conversationID, part)
   219		}
   220		for _, part := range parts {
   221			if err := ch.apiClient.SendMessage(ctx, conversationID, part); err != nil {
   222				ch.handleAPIError(err)
   223				// Remove pre-stored echo fingerprints for unsent parts so they
   224				// don't suppress genuine customer messages that happen to match.
   225				ch.forgetOutboundEcho(conversationID, part)
   226				return err
   227			}
   228		}
   229		return nil
   230	}
