test_file="$repo/internal/channels/pancake/zz_pancake_comment_repro_test.go"
cleanup() { rm -f "$test_file"; }
trap cleanup EXIT
cat > "$test_file" <<'GOEOF'
package pancake

import (
    "context"
    "encoding/json"
    "io"
    "net/http"
    "net/http/httptest"
    "strings"
    "testing"
    "time"

    "github.com/nextlevelbuilder/goclaw/internal/bus"
    "github.com/nextlevelbuilder/goclaw/internal/channels"
)

func testCommentChannel(msgBus *bus.MessageBus) (*Channel, pancakeInstanceConfig) {
    cfg := pancakeInstanceConfig{}
    cfg.Features.CommentReply = true
    ch := &Channel{
        BaseChannel: channels.NewBaseChannel(channels.TypePancake, msgBus, nil),
        config: cfg,
        pageID: "page-123",
        platform: "facebook",
    }
    return ch, cfg
}

func TestTemporaryPancakeCommentRoutesToInbound(t *testing.T) {
    msgBus := bus.New()
    target, _ := testCommentChannel(msgBus)
    router := &webhookRouter{instances: map[string]*Channel{"page-123": target}}

    body := `{"page_id":"page-123","event_type":"messaging","data":{"conversation":{"id":"page-123_user-1","type":"COMMENT","from":{"id":"user-1","name":"Customer"}},"message":{"id":"comment-1","message":"hello from comment","post_id":"post-1","from":{"id":"user-1","name":"Customer"}}}}`
    req := httptest.NewRequest(http.MethodPost, "/channels/pancake/webhook", strings.NewReader(body))
    w := httptest.NewRecorder()
    router.ServeHTTP(w, req)
    if w.Code != http.StatusOK { t.Fatalf("status = %d", w.Code) }

    ctx, cancel := context.WithTimeout(context.Background(), 100*time.Millisecond)
    defer cancel()
    msg, ok := msgBus.ConsumeInbound(ctx)
    if !ok { t.Fatal("expected COMMENT webhook to publish an inbound message") }
    if msg.Metadata["pancake_mode"] != "comment" { t.Fatalf("pancake_mode = %q", msg.Metadata["pancake_mode"]) }
    if msg.Metadata["reply_to_comment_id"] != "comment-1" { t.Fatalf("reply_to_comment_id = %q", msg.Metadata["reply_to_comment_id"]) }
}

func TestTemporaryPancakeCommentKeywordAndPostContext(t *testing.T) {
    msgBus := bus.New()
    target, cfg := testCommentChannel(msgBus)
    cfg.CommentReplyOptions.Filter = "keyword"
    cfg.CommentReplyOptions.Keywords = []string{"buy"}
    cfg.CommentReplyOptions.IncludePostContext = true
    target.config = cfg
    router := &webhookRouter{instances: map[string]*Channel{"page-123": target}}

    body := `{"page_id":"page-123","event_type":"messaging","data":{"post":{"id":"post-1","message":"Original post text"},"conversation":{"id":"conv-comment","type":"COMMENT","from":{"id":"user-1","name":"Customer"}},"message":{"id":"comment-2","message":"I want to BUY this","post_id":"post-1","from":{"id":"user-1","name":"Customer"}}}}`
    router.ServeHTTP(httptest.NewRecorder(), httptest.NewRequest(http.MethodPost, "/channels/pancake/webhook", strings.NewReader(body)))

    ctx, cancel := context.WithTimeout(context.Background(), 100*time.Millisecond)
    defer cancel()
    msg, ok := msgBus.ConsumeInbound(ctx)
    if !ok { t.Fatal("expected keyword-matching comment") }
    if !strings.Contains(msg.Content, "[Post] Original post text") { t.Fatalf("missing post context: %q", msg.Content) }
    if !strings.Contains(msg.Content, "I want to BUY this") { t.Fatalf("missing comment text: %q", msg.Content) }
}

func TestTemporaryPancakeCommentKeywordRejectsNonMatch(t *testing.T) {
    msgBus := bus.New()
    target, cfg := testCommentChannel(msgBus)
    cfg.CommentReplyOptions.Filter = "keyword"
    cfg.CommentReplyOptions.Keywords = []string{"buy"}
    target.config = cfg
    router := &webhookRouter{instances: map[string]*Channel{"page-123": target}}

    body := `{"page_id":"page-123","event_type":"messaging","data":{"conversation":{"id":"conv-comment","type":"COMMENT","from":{"id":"user-1","name":"Customer"}},"message":{"id":"comment-3","message":"just browsing","from":{"id":"user-1","name":"Customer"}}}}`
    router.ServeHTTP(httptest.NewRecorder(), httptest.NewRequest(http.MethodPost, "/channels/pancake/webhook", strings.NewReader(body)))

    ctx, cancel := context.WithTimeout(context.Background(), 50*time.Millisecond)
    defer cancel()
    if _, ok := msgBus.ConsumeInbound(ctx); ok { t.Fatal("expected non-matching keyword comment to be dropped") }
}

func TestTemporaryPancakeSendCommentAndFirstInboxOnce(t *testing.T) {
    msgBus := bus.New()
    api := NewAPIClient("user-token", "page-token", "page-123")
    var actions []string
    srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
        body, _ := io.ReadAll(r.Body)
        var payload map[string]any
        _ = json.Unmarshal(body, &payload)
        actions = append(actions, payload["action"].(string))
        w.Header().Set("Content-Type", "application/json")
        _, _ = io.WriteString(w, `{"success":true}`)
    }))
    defer srv.Close()
    api.pageV1BaseURL = srv.URL
    api.httpClient = srv.Client()

    cfg := pancakeInstanceConfig{}
    cfg.Features.FirstInbox = true
    ch := &Channel{BaseChannel: channels.NewBaseChannel(channels.TypePancake, msgBus, nil), config: cfg, apiClient: api, pageID: "page-123", platform: "facebook"}
    msg := bus.OutboundMessage{Channel: "pancake", ChatID: "conv-comment", Content: "agent reply", Metadata: map[string]string{"pancake_mode":"comment", "reply_to_comment_id":"comment-4", "sender_id":"user-1"}}
    if err := ch.Send(context.Background(), msg); err != nil { t.Fatal(err) }
    if err := ch.Send(context.Background(), msg); err != nil { t.Fatal(err) }
    got := strings.Join(actions, ",")
    if got != "reply_comment,private_reply,reply_comment" { t.Fatalf("actions = %s", got) }
}
GOEOF
cd "$repo" && go test ./internal/channels/pancake -run 'TestTemporaryPancake' -count=1
EOF
