+// ListPosts fetches the page's post list. Pancake exposes post lookup as a
+// page-level list, so callers cache and index this response by post ID.
+func (c *APIClient) ListPosts(ctx context.Context) ([]PancakePost, error) {
+       url := fmt.Sprintf("%s/pages/%s/posts", c.pageV1BaseURL, c.pageID)
+       req, err := c.newPageRequest(ctx, http.MethodGet, url, nil)
+       if err != nil {
+               return nil, fmt.Errorf("pancake: build list posts request: %w", err)
+       }
+       req.Header.Set("Content-Type", "application/json")
+
+       res, err := c.httpClient.Do(req)
+       if err != nil {
+               return nil, fmt.Errorf("pancake: list posts request failed: %w", err)
+       }
+       defer res.Body.Close()
+
+       respBody, err := io.ReadAll(res.Body)
+       if err != nil {
+               return nil, fmt.Errorf("pancake: read list posts response: %w", err)
+       }
+       if res.StatusCode >= 400 {
+               var apiErr apiError
+               if jsonErr := json.Unmarshal(respBody, &apiErr); jsonErr == nil && apiErr.Message != "" {
+                       return nil, &apiErr
+               }
+               return nil, fmt.Errorf("pancake: HTTP %d", res.StatusCode)
+       }
+
+       posts, err := decodePostsResponse(respBody)
+       if err != nil {
+               return nil, fmt.Errorf("pancake: parse list posts response: %w", err)
+       }
+       return posts, nil
+}
+
+func decodePostsResponse(body []byte) ([]PancakePost, error) {
+       var direct []PancakePost
+       if err := json.Unmarshal(body, &direct); err == nil {
+               return direct, nil
+       }
+
+       var envelope struct {
+               Data  json.RawMessage `json:"data"`
+               Posts []PancakePost   `json:"posts"`
+               Items []PancakePost   `json:"items"`
+       }
+       if err := json.Unmarshal(body, &envelope); err != nil {
+               return nil, err
+       }
+       if len(envelope.Posts) > 0 {
+               return envelope.Posts, nil
+       }
+       if len(envelope.Items) > 0 {
+               return envelope.Items, nil
+       }
+       if len(envelope.Data) == 0 || string(envelope.Data) == "null" {
+               return nil, nil
+       }
+
+       if err := json.Unmarshal(envelope.Data, &direct); err == nil {
+               return direct, nil
+       }
+       var nested struct {
+               Posts []PancakePost `json:"posts"`
+               Items []PancakePost `json:"items"`
+       }
+       if err := json.Unmarshal(envelope.Data, &nested); err != nil {
+               return nil, err
+       }
+       if len(nested.Posts) > 0 {
+               return nested.Posts, nil
+       }
+       return nested.Items, nil
+}
