--- new comment_handler.go ---
package pancake

import (
        "context"
        "fmt"
        "log/slog"
        "strings"

        "github.com/nextlevelbuilder/goclaw/internal/channels"
)

// handleCommentEvent converts a Pancake COMMENT webhook event to an inbound agent message.
func (ch *Channel) handleCommentEvent(data MessagingData) {
        if !ch.config.Features.CommentReply {
                return
        }
        if data.PageID != "" && data.PageID != ch.pageID {
                return
        }
        if data.Message.SenderID == ch.pageID {
                return
        }
        if isAssignedStaff(data.AssigneeIDs, data.Message.SenderID) {
                return
        }
        if data.Message.SenderID == "" {
                slog.Warn("pancake: comment missing sender_id, skipping", "comment_id", data.CommentID, "msg_id", data.Message.ID)
                return
        }

        commentID := data.CommentID
        if commentID == "" {
                commentID = data.Message.ID
        }
        var dedupKey string
        if commentID != "" {
                dedupKey = "comment:" + commentID
                if ch.isDup(dedupKey) {
                        slog.Debug("pancake: duplicate comment event skipped", "comment_id", commentID)
                        return
                }
        }

        if !ch.commentPassesFilter(data.Message.Content) {
                return
        }

        // Check outbound echo before buildCommentContent adds post context or prefixes.
        if ch.isRecentOutboundEcho(data.ConversationID, data.Message.Content) {
                slog.Info("pancake: skipping recent outbound comment echo",
                        "page_id", ch.pageID,
                        "conversation_id", data.ConversationID,
                        "comment_id", commentID)
                return
        }

        chatID := data.ConversationID
        if chatID == "" {
                chatID = fmt.Sprintf("%s:%s", data.PostID, data.Message.SenderID)
        }

        metadata := map[string]string{
                "pancake_mode":        "comment",
                "conversation_type":   "COMMENT",
                "platform":            data.Platform,
                "conversation_id":     data.ConversationID,
                "comment_id":          commentID,
                "post_id":             data.PostID,
                "parent_id":           data.ParentID,
                "sender_id":           data.Message.SenderID,
                "sender_name":         data.Message.SenderName,
                "reply_to_comment_id": commentID,
                "message_id":          dedupKey,
                "display_name":        channels.SanitizeDisplayName(data.Message.SenderName),
                "page_name":           ch.pageName,
        }

        ch.HandleMessage(data.Message.SenderID, chatID, ch.buildCommentContent(data), nil, metadata, "direct")
}

func (ch *Channel) commentPassesFilter(content string) bool {
        filter := strings.ToLower(strings.TrimSpace(ch.config.CommentReplyOptions.Filter))
        if filter == "" || filter == "all" {
                return true
        }
        if filter != "keyword" {
                return false
        }

        content = strings.ToLower(stripHTML(content))
        for _, keyword := range ch.config.CommentReplyOptions.Keywords {
                keyword = strings.ToLower(strings.TrimSpace(keyword))
                if keyword != "" && strings.Contains(content, keyword) {
                        return true
                }
        }
        return false
}

func (ch *Channel) buildCommentContent(data MessagingData) string {
        content := buildMessageContent(data)
        if !ch.config.CommentReplyOptions.IncludePostContext {
                return content
        }

        postText := data.Post.Text()
        if postText == "" && ch.postFetcher != nil && data.PostID != "" {
                ctx := ch.stopCtx
                if ctx == nil {
                        ctx = context.Background()
                }
                post, err := ch.postFetcher.GetPost(ctx, data.PostID)
                if err == nil && post != nil {
                        postText = post.Text()
                } else if err != nil {
                        slog.Warn("pancake: fetch post context failed", "post_id", data.PostID, "err", err)
                }
        }
        if postText == "" {
                return content
        }
        return "[Post] " + stripHTML(postText) + "\n\n" + content
}
--- new post_fetcher.go ---
package pancake

import (
        "context"
        "sync"
        "time"

        "golang.org/x/sync/singleflight"
)

const defaultPostCacheTTL = 15 * time.Minute

// postCacheEntry holds the page's post list indexed by canonical post ID.
type postCacheEntry struct {
        posts     map[string]*PancakePost
        expiresAt time.Time
}

// PostFetcher fetches and caches Pancake post content for comment context.
// Pancake exposes posts as a page-level list, so concurrent misses share one
// singleflight key ("posts") instead of fetching each post independently.
type PostFetcher struct {
        apiClient *APIClient
        cacheTTL  time.Duration
        cache     sync.Map           // "posts" → *postCacheEntry
        sfGroup   singleflight.Group // coalesces concurrent page post-list fetches
}

// NewPostFetcher creates a PostFetcher with the given cache TTL string.
func NewPostFetcher(client *APIClient, cacheTTLStr string) *PostFetcher {
        ttl := defaultPostCacheTTL
        if cacheTTLStr != "" {
                if d, err := time.ParseDuration(cacheTTLStr); err == nil && d > 0 {
                        ttl = d
                }
        }
        return &PostFetcher{apiClient: client, cacheTTL: ttl}
}

// GetPost returns the requested post from the cached page post list.
func (pf *PostFetcher) GetPost(ctx context.Context, postID string) (*PancakePost, error) {
        if pf == nil || pf.apiClient == nil || postID == "" {
                return nil, nil
        }
        posts, err := pf.getPosts(ctx)
        if err != nil {
                return nil, err
        }
        return posts[postID], nil
}

func (pf *PostFetcher) getPosts(ctx context.Context) (map[string]*PancakePost, error) {
        const cacheKey = "posts"
        if v, ok := pf.cache.Load(cacheKey); ok {
                entry := v.(*postCacheEntry)
                if time.Now().Before(entry.expiresAt) {
                        return entry.posts, nil
                }
                pf.cache.Delete(cacheKey)
        }

        val, err, _ := pf.sfGroup.Do(cacheKey, func() (any, error) {
                if v, ok := pf.cache.Load(cacheKey); ok {
                        entry := v.(*postCacheEntry)
                        if time.Now().Before(entry.expiresAt) {
                                return entry.posts, nil
                        }
                }

                list, err := pf.apiClient.ListPosts(ctx)
                if err != nil {
                        return nil, err
                }
                posts := make(map[string]*PancakePost, len(list))
                for i := range list {
                        post := &list[i]
                        if id := post.CanonicalID(); id != "" {
                                posts[id] = post
                        }
                }
                pf.cache.Store(cacheKey, &postCacheEntry{posts: posts, expiresAt: time.Now().Add(pf.cacheTTL)})
                return posts, nil
        })
        if err != nil {
                return nil, err
        }
        return val.(map[string]*PancakePost), nil
}
